const cardVariants = {
  hidden: { opacity: 0, y: 20 },
  visible: {
    opacity: 1,
    y: 0,
    transition: { duration: 0.6, ease: "easeOut" }
  },
  hover: {
    y: -10,
    transition: { duration: 0.3, type: 'spring', stiffness: 300 }
  }
};

const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.2
    }
  }
};

const Sales = () => {
  const [isLoading, setIsLoading] = useState(true);
  
  useEffect(() => {
    const timer = setTimeout(() => {
      setIsLoading(false);
    }, 1000);
    
    return () => clearTimeout(timer);
  }, []);
  
  const handleExternalRedirect = (url) => {
    window.location.href = url;
  };
  
  if (isLoading) {
    return (
      <SalesSection>
        <ShimmerHeader />
        <ShimmerHeader style={{ width: '40%', height: '30px', marginBottom: '15px' }} />
        <ShimmerHeader style={{ width: '70%', height: '20px', marginBottom: '60px' }} />
        
        <ShimmerGrid>
          {Array(3).fill(0).map((_, index) => (
            <ShimmerCard key={index} />
          ))}
        </ShimmerGrid>
      </SalesSection>
    );
  }
  
  return (
    <SalesSection>
      <Badge>⚡ Prospector acelera suas vendas com IA</Badge>
      
      <Title
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6 }}
      >
        Prospector é a prospecção inteligente que sua empresa precisa
      </Title>
      
      <Subtitle
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6, delay: 0.1 }}
      >
        Venda mais sem complicação.
      </Subtitle>
      
      <Description
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6, delay: 0.2 }}
      >
        Deixe o Prospector automatizar a prospecção para que sua equipe se concentre no
        que realmente importa: fechar negócios.
      </Description>
      
      <CardsContainer
        variants={containerVariants}
        initial="hidden"
        whileInView="visible"
        viewport={{ once: true, amount: 0.2 }}
      >
        <motion.div
          variants={cardVariants}
          whileHover="hover"
        >
          <Card>
            <IconContainer>
              <BsFilter />
            </IconContainer>
            <CardTitle>Outbound</CardTitle>
            <CardDescription>
              O Prospector encontra e qualifica os contatos certos para você. Ele inicia a abordagem automatizada, responde mensagens e agenda reuniões, sem intervenção manual.
            </CardDescription>
            <ActionButton
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={() => handleExternalRedirect('https://app.prospector.business/register')}
            >
              Automatize seu Outbound <span>⚡</span>
            </ActionButton>
          </Card>
        </motion.div>
        
        <motion.div
          variants={cardVariants}
          whileHover="hover"
        >
          <Card>
            <IconContainer>
              <BsMegaphone />
            </IconContainer>
            <CardTitle>Inbound</CardTitle>
            <CardDescription>
              O tempo de resposta define suas conversões. Nossa IA interage com leads assim que entram no funil, qualificando e direcionando para o próximo passo da jornada de compra.
            </CardDescription>
            <ActionButton
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={() => handleExternalRedirect('https://app.prospector.business/register')}
            >
              Otimize seu Inbound <span>⚡</span>
            </ActionButton>
          </Card>
        </motion.div>
        
        <motion.div
          variants={cardVariants}
          whileHover="hover"
        >
          <Card>
            <IconContainer>
              <BsChatDots />
            </IconContainer>
            <CardTitle>ChatBots para leads</CardTitle>
            <CardDescription>
              Transforme visitantes do seu site em oportunidades reais. O Prospector interage com usuários, responde dúvidas e impulsiona suas vendas automaticamente.
            </CardDescription>
            <ActionButton
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={() => handleExternalRedirect('https://app.prospector.business/register')}
            >
              Implemente Chatbots <span>⚡</span>
            </ActionButton>
          </Card>
        </motion.div>
      </CardsContainer>
    </SalesSection>
  );
};

